import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { cities, spaces } from '../data/spaces';

export default function Locations() {
  const cityToCount = cities.map((c) => ({ city: c, count: spaces.filter((s) => s.city === c).length }));
  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 w-full px-6 md:px-12 lg:px-16 py-10">
        <h1 className="text-3xl font-bold text-gray-900">Find WorkNest in your city</h1>
        <div className="mt-8 grid grid-cols-1 md:grid-cols-3 gap-6">
          {cityToCount.map(({ city, count }) => (
            <a key={city} href={`/search`} className="p-6 rounded-2xl border border-gray-100 shadow-card hover:-translate-y-0.5 transition block">
              <div className="h-28 rounded-xl bg-gradient-to-br from-brand-100 to-brand-200" />
              <div className="mt-4 flex items-center justify-between">
                <div className="text-lg font-semibold text-gray-900">{city}</div>
                <div className="text-sm text-gray-600">{count} spaces</div>
              </div>
            </a>
          ))}
        </div>
      </main>
      <Footer />
    </div>
  );
}
